// ============================================================
// Merge sort — O(n log n) time, O(n) space
// ============================================================

function mergeSort(arr) {
  // Base case: an array of 0 or 1 element is already sorted
  if (arr.length <= 1) return arr;

  // Divide: split into two halves
  const mid = Math.floor(arr.length / 2);
  const left  = mergeSort(arr.slice(0, mid));
  const right = mergeSort(arr.slice(mid));

  // Conquer: merge the two sorted halves
  return merge(left, right);
}

function merge(a, b) {
  const out = [];
  let i = 0, j = 0;

  // Walk both arrays with two pointers, take the smaller front item
  while (i < a.length && j < b.length) {
    if (a[i] <= b[j]) out.push(a[i++]);
    else              out.push(b[j++]);
  }

  // Drain whichever side still has items
  while (i < a.length) out.push(a[i++]);
  while (j < b.length) out.push(b[j++]);

  return out;
}

console.log(mergeSort([38, 27, 43, 3, 9, 82, 10]));
// → [3, 9, 10, 27, 38, 43, 82]

console.log(mergeSort([5, 5, 1, 1, 3, 3, 2, 2]));
// → [1, 1, 2, 2, 3, 3, 5, 5]  (note: merge sort is STABLE)

// Comparing merge sort against O(n²) bubble sort on the same input.
// Watch how the gap explodes as n grows.

function bubbleSort(arr) {
  arr = [...arr];
  for (let i = 0; i < arr.length; i++) {
    for (let j = 0; j < arr.length - i - 1; j++) {
      if (arr[j] > arr[j + 1]) {
        [arr[j], arr[j + 1]] = [arr[j + 1], arr[j]];
      }
    }
  }
  return arr;
}

function mergeSort(arr) {
  if (arr.length <= 1) return arr;
  const mid = Math.floor(arr.length / 2);
  return merge(mergeSort(arr.slice(0, mid)), mergeSort(arr.slice(mid)));
}
function merge(a, b) {
  const out = []; let i = 0, j = 0;
  while (i < a.length && j < b.length) out.push(a[i] <= b[j] ? a[i++] : b[j++]);
  return [...out, ...a.slice(i), ...b.slice(j)];
}

function randomArr(n) {
  return Array.from({ length: n }, () => Math.floor(Math.random() * 10000));
}

for (const n of [100, 1000, 5000]) {
  const arr = randomArr(n);

  let t0 = performance.now();
  bubbleSort(arr);
  let bubbleMs = performance.now() - t0;

  t0 = performance.now();
  mergeSort(arr);
  let mergeMs = performance.now() - t0;

  console.log(`n=${n.toString().padStart(5)}  bubble: ${bubbleMs.toFixed(2)}ms  merge: ${mergeMs.toFixed(2)}ms`);
}

