// Tournament-style pairwise merge: log k rounds, n work per round → O(n log k)
function mergeKArrays(arrs) {
  if (arrs.length === 0) return [];
  while (arrs.length > 1) {
    const next = [];
    for (let i = 0; i < arrs.length; i += 2) {
      if (i + 1 < arrs.length) next.push(merge(arrs[i], arrs[i + 1]));
      else                     next.push(arrs[i]);
    }
    arrs = next;
  }
  return arrs[0];
}

function merge(a, b) {
  const out = []; let i = 0, j = 0;
  while (i < a.length && j < b.length) out.push(a[i] <= b[j] ? a[i++] : b[j++]);
  return [...out, ...a.slice(i), ...b.slice(j)];
}
